import{bQ as a,aL as s,u as d,G as n}from"./chunks/framework.D06dwy5q.js";const e="/kb/assets/01-architecture-shapes.CzTIRsHm.png",r="/kb/assets/02-read-write-split-lag.DkC9yN0T.png",p="/kb/assets/03-sharding-cost.DVZSQ1d2.png",i="/kb/assets/04-enterprise-504-path.BBiCDqCD.png",g=JSON.parse('{"title":"第 14 讲｜企业架构形态","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/14-企业架构形态.md","filePath":"00.互联网与架构基础/14-企业架构形态.md","lastUpdated":null}'),l={name:"00.互联网与架构基础/14-企业架构形态.md"};function o(h,t,c,b,E,A){return s(),d("div",null,[...t[0]||(t[0]=[n('<h1 id="第-14-讲-企业架构形态" tabindex="-1">第 14 讲｜企业架构形态 <a class="header-anchor" href="#第-14-讲-企业架构形态" aria-label="Permalink to &quot;第 14 讲｜企业架构形态&quot;">​</a></h1><p>公司里的系统不会都长一个样——内部小工具可能就是一台机器加一个数据库,核心交易系统则涉及多机房、灰度发布、审计、容灾、专门的发布流程。<strong>架构形态由业务量、可用性要求、团队规模、历史包袱共同决定</strong>,不存在一种通用的&quot;标准架构&quot;。</p><p>单机、主备、集群、读写分离、分库分表、缓存、消息队列、微服务、容器化——这些形态是在不同压力阶段被逐步引入的。<strong>搞清楚每种形态各自解决什么问题、什么时候该升级到下一阶段,比直接套用一套&quot;高大上架构&quot;更重要</strong>。</p><p>本讲按业务规模递进,从单机到大型分布式架构,讲清楚每一种形态的适用场景、关键能力、典型陷阱。</p><h2 id="一、单机形态" tabindex="-1">一、单机形态 <a class="header-anchor" href="#一、单机形态" aria-label="Permalink to &quot;一、单机形态&quot;">​</a></h2><p>最简单的形态——入口、应用、数据库、文件全部在一台或少量几台服务器上:</p><p><img src="'+e+'" alt="企业架构从单机主备集群逐步演进"></p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20subgraph%20Server%5B%22%E4%B8%80%E5%8F%B0%E6%9C%8D%E5%8A%A1%E5%99%A8%22%5D%0A%20%20%20%20Nginx%5B%22Nginx%22%5D%0A%20%20%20%20App%5B%22%E5%BA%94%E7%94%A8%22%5D%0A%20%20%20%20DB%5B(%22%E6%95%B0%E6%8D%AE%E5%BA%93%22)%5D%0A%20%20%20%20Files%5B%22%E6%96%87%E4%BB%B6%E7%9B%AE%E5%BD%95%22%5D%0A%20%20end%0A%20%20User%20--%3E%20Nginx%0A%20%20Nginx%20--%3E%20App%0A%20%20App%20--%3E%20DB%0A%20%20Nginx%20--%3E%20Files%0A"></div><h3 id="单机形态的合理场景" tabindex="-1">单机形态的合理场景 <a class="header-anchor" href="#单机形态的合理场景" aria-label="Permalink to &quot;单机形态的合理场景&quot;">​</a></h3><ul><li>内部小工具、运维平台</li><li>临时搭建的环境</li><li>项目早期阶段</li><li>测试 / 演示环境</li><li>个人项目、博客</li><li>边缘节点(IoT、门店本地)</li></ul><p><strong>单机不是&quot;落后&quot;,而是合理简单</strong>。在适合的场景下,单机的运维成本、调试便利性、链路清晰度都远超复杂架构。</p><h3 id="单机最大的优势是路径短" tabindex="-1">单机最大的优势是路径短 <a class="header-anchor" href="#单机最大的优势是路径短" aria-label="Permalink to &quot;单机最大的优势是路径短&quot;">​</a></h3><ul><li>所有日志在一台机器上 → <code>tail -f /var/log/*</code> 一处搞定</li><li>配置在一处 → 修改不需要分发</li><li>备份和恢复流程简单 → 一份镜像 + 一份数据库就完整</li><li>调试方便 → <code>ssh</code> 进去什么都能看</li></ul><h3 id="单机要补的不是-加机器-是底线能力" tabindex="-1">单机要补的不是&quot;加机器&quot;,是底线能力 <a class="header-anchor" href="#单机要补的不是-加机器-是底线能力" aria-label="Permalink to &quot;单机要补的不是&quot;加机器&quot;,是底线能力&quot;">​</a></h3><p>单机模式真正需要的不是&quot;扩展&quot;,而是<strong>底线能力</strong>:</p><table tabindex="0"><thead><tr><th>能力</th><th>解决什么</th></tr></thead><tbody><tr><td>监控告警</td><td>服务存活、磁盘、内存、CPU 告警</td></tr><tr><td>备份</td><td>数据库定时备份 + 异地存储</td></tr><tr><td>重建步骤文档</td><td>机器挂了后如何快速重建一台</td></tr><tr><td>服务自启动</td><td>systemd 配置,机器重启服务自动起来</td></tr><tr><td>日志轮转</td><td>logrotate 防止日志撑爆磁盘</td></tr><tr><td>关键配置版本管理</td><td>配置进 Git,丢了能恢复</td></tr></tbody></table><p><strong>单机不丢人,单机没备份才丢人</strong>——能用简单方案解决的问题,不要用复杂方案。</p><h3 id="单机的天花板" tabindex="-1">单机的天花板 <a class="header-anchor" href="#单机的天花板" aria-label="Permalink to &quot;单机的天花板&quot;">​</a></h3><p>单机形态的限制:</p><ul><li><strong>单点故障</strong> — 这台机器挂,全停</li><li><strong>资源上限</strong> — 单机配置有物理上限</li><li><strong>发布影响</strong> — 发布时全部用户都跟着停</li><li><strong>故障域大</strong> — 一个组件出问题影响全局</li></ul><p>业务真正增长到需要 99.9% 可用性、流量增长到单机扛不住时,才考虑升级到下一阶段。</p><h2 id="二、主备形态" tabindex="-1">二、主备形态 <a class="header-anchor" href="#二、主备形态" aria-label="Permalink to &quot;二、主备形态&quot;">​</a></h2><p>主备(Active-Standby)给关键组件准备一个<strong>接管节点</strong>——主节点正常服务,备节点同步数据或待命:</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20VIP%5B%22VIP%22%5D%0A%20%20Primary%5B%22%E4%B8%BB%E8%8A%82%E7%82%B9%3Cbr%2F%3E%E5%AF%B9%E5%A4%96%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20Standby%5B%22%E5%A4%87%E8%8A%82%E7%82%B9%3Cbr%2F%3E%E6%95%B0%E6%8D%AE%E5%90%8C%E6%AD%A5%22%5D%0A%0A%20%20User%20--%3E%20VIP%0A%20%20VIP%20--%3E%20Primary%0A%20%20Primary%20-.-%3E%7C%22%E5%A4%8D%E5%88%B6%22%7C%20Standby%0A"></div><h3 id="常见的主备组件" tabindex="-1">常见的主备组件 <a class="header-anchor" href="#常见的主备组件" aria-label="Permalink to &quot;常见的主备组件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对象</th><th>主备实现方式</th></tr></thead><tbody><tr><td>数据库</td><td>主库写入,从库同步,故障时提升从库为主</td></tr><tr><td>入口负载均衡</td><td>Keepalived + VIP 漂移</td></tr><tr><td>文件服务</td><td>主备存储 + 同步复制,或共享存储</td></tr><tr><td>Redis</td><td>主从 + Sentinel(哨兵)</td></tr><tr><td>共享存储(NAS/Ceph)</td><td>主备节点共享后端存储</td></tr></tbody></table><h3 id="主备不只是-多装一台机器" tabindex="-1">主备不只是&quot;多装一台机器&quot; <a class="header-anchor" href="#主备不只是-多装一台机器" aria-label="Permalink to &quot;主备不只是&quot;多装一台机器&quot;&quot;">​</a></h3><p>真正可用的主备方案需要一整套配套:</p><table tabindex="0"><thead><tr><th>配套能力</th><th>作用</th></tr></thead><tbody><tr><td>心跳检测</td><td>持续监控主节点状态</td></tr><tr><td>切换脚本</td><td>自动化执行切换流程</td></tr><tr><td>旧主隔离</td><td>防止脑裂(下面详述)</td></tr><tr><td>客户端连接刷新</td><td>应用连接池主动重连新主</td></tr><tr><td>切换后验证</td><td>写入测试、关键路径测试</td></tr><tr><td>切换演练</td><td>定期手工触发切换,验证流程可用</td></tr></tbody></table><p>任何一环缺失,真故障时切换都做不下去。</p><h3 id="数据库主备切换的关键-旧主处理" tabindex="-1">数据库主备切换的关键:旧主处理 <a class="header-anchor" href="#数据库主备切换的关键-旧主处理" aria-label="Permalink to &quot;数据库主备切换的关键:旧主处理&quot;">​</a></h3><p>数据库主备切换里最容易漏的是<strong>旧主处理</strong>。如果旧主只是网络短暂断开,网络恢复后它还以为自己是主,继续接收写请求,而新主也在接收写请求——<strong>脑裂(双写)</strong>,数据冲突。</p><p>切换流程必须明确决定:</p><table tabindex="0"><thead><tr><th>旧主处理方式</th><th>适用场景</th></tr></thead><tbody><tr><td>关停</td><td>确认无法恢复 / 严重故障</td></tr><tr><td>设为只读</td><td>旧主可能恢复,但禁止写入</td></tr><tr><td>网络隔离(Fencing)</td><td>通过 iptables 或物理隔离阻止旧主写入</td></tr><tr><td>重新作为从库接回</td><td>旧主硬件正常,数据用复制追平</td></tr></tbody></table><p><strong>不同选择对应不同的恢复路径,必须提前想清楚,出事时不能再讨论</strong>。</p><h2 id="三、集群形态" tabindex="-1">三、集群形态 <a class="header-anchor" href="#三、集群形态" aria-label="Permalink to &quot;三、集群形态&quot;">​</a></h2><p>集群用多个节点共同提供服务。最容易理解的是 Web 集群——多个<strong>无状态</strong>应用实例挂在负载均衡后面:</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20LB%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20App1%5B%22%E5%BA%94%E7%94%A8%E5%AE%9E%E4%BE%8B%201%22%5D%0A%20%20App2%5B%22%E5%BA%94%E7%94%A8%E5%AE%9E%E4%BE%8B%202%22%5D%0A%20%20App3%5B%22%E5%BA%94%E7%94%A8%E5%AE%9E%E4%BE%8B%203%22%5D%0A%20%20Cache%5B(%22Redis%22)%5D%0A%20%20DB%5B(%22%E6%95%B0%E6%8D%AE%E5%BA%93%22)%5D%0A%20%20MQ%5B(%22%E6%B6%88%E6%81%AF%E9%98%9F%E5%88%97%22)%5D%0A%0A%20%20User%20--%3E%20LB%0A%20%20LB%20--%3E%20App1%0A%20%20LB%20--%3E%20App2%0A%20%20LB%20--%3E%20App3%0A%20%20App1%20--%3E%20Cache%0A%20%20App2%20--%3E%20Cache%0A%20%20App1%20--%3E%20DB%0A%20%20App2%20--%3E%20DB%0A%20%20App3%20--%3E%20MQ%0A"></div><h3 id="无状态应用最适合集群化" tabindex="-1">无状态应用最适合集群化 <a class="header-anchor" href="#无状态应用最适合集群化" aria-label="Permalink to &quot;无状态应用最适合集群化&quot;">​</a></h3><p>无状态(Stateless)的关键特征:</p><ul><li>实例不保存关键状态</li><li>任意请求打到任意实例都能处理</li><li>状态从数据库、缓存、对象存储取</li><li>挂一个少一个,加一个多一个,扩缩容自由</li></ul><p>无状态应用的集群能力是<strong>云原生时代所有弹性能力</strong>(K8s 自动扩缩、滚动更新、健康检查替换)的基础。</p><h3 id="有状态组件的集群-不能一概而论" tabindex="-1">有状态组件的集群:不能一概而论 <a class="header-anchor" href="#有状态组件的集群-不能一概而论" aria-label="Permalink to &quot;有状态组件的集群:不能一概而论&quot;">​</a></h3><p>有状态组件的集群形态因组件而异,<strong>不能笼统说&quot;做了集群就高可用了&quot;</strong>:</p><table tabindex="0"><thead><tr><th>组件</th><th>集群形态</th></tr></thead><tbody><tr><td>MySQL</td><td>主从复制、组复制(MGR)、Galera、分片(Vitess)</td></tr><tr><td>PostgreSQL</td><td>流复制、Patroni、Citus</td></tr><tr><td>Redis</td><td>主从 + Sentinel、Redis Cluster(分片)</td></tr><tr><td>MongoDB</td><td>Replica Set、Sharded Cluster</td></tr><tr><td>Kafka</td><td>多 broker + 分区副本</td></tr><tr><td>Elasticsearch</td><td>分片 + 副本</td></tr><tr><td>etcd</td><td>Raft 一致性</td></tr></tbody></table><p><strong>每种集群形态都要单独理解</strong>:数据归属、复制方式、故障转移机制、扩缩容步骤。MySQL 主从集群、MGR 集群、TiDB 集群,完全不是一回事——运维方法、故障处理、性能特点都不同。</p><h2 id="四、读写分离" tabindex="-1">四、读写分离 <a class="header-anchor" href="#四、读写分离" aria-label="Permalink to &quot;四、读写分离&quot;">​</a></h2><p>读写分离把<strong>写请求交给主库,读请求分摊到从库</strong>,适合&quot;读多写少&quot;场景:</p><p><img src="'+r+`" alt="读写分离要处理复制延迟和请求路由"></p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20App%5B%22%E5%BA%94%E7%94%A8%22%5D%0A%20%20Primary%5B(%22%E4%B8%BB%E5%BA%93%3Cbr%2F%3E%E8%AF%BB%2B%E5%86%99%22)%5D%0A%20%20Replica1%5B(%22%E4%BB%8E%E5%BA%93%201%22)%5D%0A%20%20Replica2%5B(%22%E4%BB%8E%E5%BA%93%202%22)%5D%0A%20%20Replica3%5B(%22%E4%BB%8E%E5%BA%93%203%22)%5D%0A%0A%20%20App%20--%3E%7C%22%E5%86%99%E5%85%A5%22%7C%20Primary%0A%20%20App%20--%3E%7C%22%E8%AF%BB%E5%8F%96%22%7C%20Replica1%0A%20%20App%20--%3E%7C%22%E8%AF%BB%E5%8F%96%22%7C%20Replica2%0A%20%20App%20--%3E%7C%22%E8%AF%BB%E5%8F%96%22%7C%20Replica3%0A%20%20Primary%20-.-%3E%7C%22%E5%A4%8D%E5%88%B6%22%7C%20Replica1%0A%20%20Primary%20-.-%3E%7C%22%E5%A4%8D%E5%88%B6%22%7C%20Replica2%0A%20%20Primary%20-.-%3E%7C%22%E5%A4%8D%E5%88%B6%22%7C%20Replica3%0A"></div><h3 id="读写分离的核心问题-复制延迟" tabindex="-1">读写分离的核心问题:复制延迟 <a class="header-anchor" href="#读写分离的核心问题-复制延迟" aria-label="Permalink to &quot;读写分离的核心问题:复制延迟&quot;">​</a></h3><p>主从复制是异步或半同步的——<strong>主库写入后,从库需要时间同步</strong>。这段时间内访问从库会读到旧数据。</p><p>最经典的体验问题:<strong>写后立即读</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户:修改头像(写主库,成功)</span></span>
<span class="line"><span>0.5 秒后:刷新个人页(读请求路由到延迟从库)</span></span>
<span class="line"><span>从库还未同步:返回旧头像</span></span>
<span class="line"><span>用户:&quot;我刚改的怎么没生效?&quot;</span></span></code></pre></div><h3 id="不同请求类型的路由策略" tabindex="-1">不同请求类型的路由策略 <a class="header-anchor" href="#不同请求类型的路由策略" aria-label="Permalink to &quot;不同请求类型的路由策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>路由策略</th></tr></thead><tbody><tr><td>写操作</td><td>强制走主库</td></tr><tr><td>写后立即读(同一用户的相关读)</td><td>短时间内强制读主库</td></tr><tr><td>普通列表查询、详情查询</td><td>走从库分摊压力</td></tr><tr><td>重型报表查询</td><td>走专门的只读库或离线数仓</td></tr><tr><td>复制延迟过大时</td><td>暂停读从库,等复制追上</td></tr><tr><td>强一致要求(支付、扣款)</td><td>全部走主库</td></tr></tbody></table><h3 id="读写分离的工程要求" tabindex="-1">读写分离的工程要求 <a class="header-anchor" href="#读写分离的工程要求" aria-label="Permalink to &quot;读写分离的工程要求&quot;">​</a></h3><p>接入读写分离需要同步设计:</p><table tabindex="0"><thead><tr><th>能力</th><th>作用</th></tr></thead><tbody><tr><td>SQL 路由层</td><td>按 SQL 类型(写/读)和场景选择主从</td></tr><tr><td>连接池管理</td><td>主从分别维护连接池</td></tr><tr><td>复制延迟监控</td><td>持续监控 <code>Seconds_Behind_Master</code></td></tr><tr><td>自动降级</td><td>延迟过大时自动切回主库</td></tr><tr><td>故障切换流程</td><td>主库故障时的提升流程</td></tr></tbody></table><p><strong>&quot;把一个从库地址塞进配置文件&quot;不是读写分离</strong>——这种&quot;伪读写分离&quot;出问题时排查极其困难,因为应用根本不知道某次读为什么读到了旧数据。</p><h2 id="五、分库分表" tabindex="-1">五、分库分表 <a class="header-anchor" href="#五、分库分表" aria-label="Permalink to &quot;五、分库分表&quot;">​</a></h2><p>当单表数据量太大(千万级以上)、单库写入压力太高、或者历史与在线数据互相影响时,会走到<strong>分库分表</strong>。</p><p><img src="`+p+`" alt="分库分表解决容量但带来查询和事务代价"></p><h3 id="拆分策略" tabindex="-1">拆分策略 <a class="header-anchor" href="#拆分策略" aria-label="Permalink to &quot;拆分策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>拆分维度</th><th>拆分方式</th><th>适用场景</th></tr></thead><tbody><tr><td>按用户 ID 哈希</td><td><code>user_id % N</code> 决定分片</td><td>数据按用户均匀分散</td></tr><tr><td>按时间</td><td>每月一张表,每年一个库</td><td>日志、订单等时间序列数据</td></tr><tr><td>按业务域</td><td>用户库、订单库、支付库</td><td>业务模块清晰</td></tr><tr><td>范围分片</td><td>按 ID 范围</td><td>数据有自然范围</td></tr><tr><td>一致性哈希</td><td>用哈希环</td><td>扩缩容影响最小</td></tr></tbody></table><h3 id="分库分表的真实代价" tabindex="-1">分库分表的真实代价 <a class="header-anchor" href="#分库分表的真实代价" aria-label="Permalink to &quot;分库分表的真实代价&quot;">​</a></h3><p>分库分表能分散压力,但<strong>代价是查询方式被彻底改变</strong>:</p><table tabindex="0"><thead><tr><th>单库简单的事,分片后变难</th><th>影响</th></tr></thead><tbody><tr><td><code>SELECT ... WHERE id = ?</code></td><td>需要先算出在哪个分片</td></tr><tr><td>跨分片 JOIN</td><td>几乎不可能,改成应用层聚合</td></tr><tr><td>跨分片分页</td><td>性能崩,所有分片都要查</td></tr><tr><td>全局唯一 ID</td><td>不能用 AUTO_INCREMENT,要 Snowflake 等方案</td></tr><tr><td>全局事务</td><td>跨库事务复杂,通常放弃</td></tr><tr><td>跨分片聚合</td><td>COUNT、SUM 需要聚合所有分片</td></tr><tr><td>扩容迁移</td><td>数据重新分布,复杂且影响业务</td></tr></tbody></table><p>举例:&quot;查所有用户最近 10 条订单&quot;在单库就是简单的 ORDER BY + LIMIT,<strong>分片后需要查所有分片再合并排序</strong>——性能与复杂度同时崩坏。</p><h3 id="走到分库分表前-先做完这些" tabindex="-1">走到分库分表前,先做完这些 <a class="header-anchor" href="#走到分库分表前-先做完这些" aria-label="Permalink to &quot;走到分库分表前,先做完这些&quot;">​</a></h3><p><strong>很多系统其实根本不需要分库分表</strong>。在分片前,有一堆更低成本的优化:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单表大 → 加索引、改慢 SQL → 命中索引,问题解决</span></span>
<span class="line"><span>              ↓ 仍然慢</span></span>
<span class="line"><span>归档历史数据(冷数据搬到归档表)→ 在线表减小,问题解决</span></span>
<span class="line"><span>              ↓ 仍然慢</span></span>
<span class="line"><span>加缓存(热点数据进 Redis)→ 数据库压力下降,问题解决</span></span>
<span class="line"><span>              ↓ 仍然慢</span></span>
<span class="line"><span>读写分离 → 读压力分摊,问题解决</span></span>
<span class="line"><span>              ↓ 仍然慢</span></span>
<span class="line"><span>垂直分库(按业务拆库)→ 单库压力下降,问题解决</span></span>
<span class="line"><span>              ↓ 仍然解决不了</span></span>
<span class="line"><span>水平分库分表 → 不得不上的最后一步</span></span></code></pre></div><p><strong>只有前面所有手段都做完仍然撑不住,才真正进入分片</strong>。</p><h3 id="分库分表中间件" tabindex="-1">分库分表中间件 <a class="header-anchor" href="#分库分表中间件" aria-label="Permalink to &quot;分库分表中间件&quot;">​</a></h3><p>走到分库分表的项目,需要专门的中间件:</p><table tabindex="0"><thead><tr><th>中间件</th><th>类型</th></tr></thead><tbody><tr><td>ShardingSphere(原 ShardingJDBC)</td><td>JDBC 层,Java 生态主流</td></tr><tr><td>MyCAT</td><td>Proxy 层</td></tr><tr><td>Vitess</td><td>Proxy 层,YouTube 出品,K8s 友好</td></tr><tr><td>TiDB</td><td>分布式数据库,自带分片</td></tr><tr><td>OceanBase</td><td>分布式数据库</td></tr></tbody></table><p><strong>新项目对分片有需求时,优先考虑分布式数据库(TiDB、OceanBase)</strong>——比自己用 ShardingSphere 拼一套要省心得多。</p><h2 id="六、缓存与消息队列" tabindex="-1">六、缓存与消息队列 <a class="header-anchor" href="#六、缓存与消息队列" aria-label="Permalink to &quot;六、缓存与消息队列&quot;">​</a></h2><p>缓存挡住重复读,消息队列承接异步任务和削峰。这两类组件在架构里位置不同,但常常一起出现。</p><h3 id="缓存" tabindex="-1">缓存 <a class="header-anchor" href="#缓存" aria-label="Permalink to &quot;缓存&quot;">​</a></h3><table tabindex="0"><thead><tr><th>用途</th><th>说明</th></tr></thead><tbody><tr><td>数据缓存</td><td>热点数据放 Redis,挡住反复查询</td></tr><tr><td>会话存储</td><td>用户登录状态</td></tr><tr><td>分布式锁</td><td>控制并发修改共享资源</td></tr><tr><td>计数器</td><td>限流、统计、UV/PV</td></tr><tr><td>排行榜</td><td>Redis ZSet</td></tr><tr><td>去重</td><td>Redis Set、Bloom Filter</td></tr></tbody></table><p><strong>缓存接入后要面对的问题</strong>:</p><table tabindex="0"><thead><tr><th>问题</th><th>处理</th></tr></thead><tbody><tr><td>数据过期与一致性</td><td>数据库更新后主动失效缓存</td></tr><tr><td>缓存穿透</td><td>缓存空值、布隆过滤器</td></tr><tr><td>缓存击穿</td><td>互斥锁、热点 key 永不过期</td></tr><tr><td>缓存雪崩</td><td>过期时间加随机抖动</td></tr><tr><td>大 key</td><td>单个 value 过大,影响性能</td></tr></tbody></table><p>详见 <a href="/kb/00.互联网与架构基础/06-数据库出现">第 6 讲 数据库的出现</a> 第五节。</p><h3 id="消息队列" tabindex="-1">消息队列 <a class="header-anchor" href="#消息队列" aria-label="Permalink to &quot;消息队列&quot;">​</a></h3><table tabindex="0"><thead><tr><th>消息系统</th><th>适用场景</th><th>主要监控点</th></tr></thead><tbody><tr><td>RabbitMQ</td><td>后台任务、可靠投递、传统业务</td><td>队列长度、未确认消息、消费者数</td></tr><tr><td>Kafka</td><td>日志流、事件流、大吞吐数据管道</td><td>消费 lag、分区均衡</td></tr><tr><td>Redis Stream/List</td><td>轻量内部任务</td><td>队列长度</td></tr><tr><td>RocketMQ</td><td>国内电商、金融场景</td><td>类似 Kafka</td></tr></tbody></table><h3 id="异步任务排查的不同思路" tabindex="-1">异步任务排查的不同思路 <a class="header-anchor" href="#异步任务排查的不同思路" aria-label="Permalink to &quot;异步任务排查的不同思路&quot;">​</a></h3><p>接入消息队列后,<strong>异步任务的排查思路与同步请求完全不同</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户:点&quot;生成报表&quot;</span></span>
<span class="line"><span>接口:立即返回 task_id = 12345</span></span>
<span class="line"><span>前端:显示&quot;生成中&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>后台:消费者从队列取出任务 12345</span></span>
<span class="line"><span>后台:执行报表生成</span></span>
<span class="line"><span>后台:更新任务状态为 done</span></span>
<span class="line"><span></span></span>
<span class="line"><span>前端:轮询任务状态接口,看到 done</span></span>
<span class="line"><span>前端:展示报表</span></span></code></pre></div><p>如果&quot;生成中&quot;一直转圈,排查的不是接口而是:</p><table tabindex="0"><thead><tr><th>检查项</th><th>含义</th></tr></thead><tbody><tr><td>任务记录</td><td>数据库里任务的状态是什么</td></tr><tr><td>消息队列积压</td><td>消费者是否在消费</td></tr><tr><td>消费者实例</td><td>后台服务是否正常运行</td></tr><tr><td>消费者日志</td><td>是否有处理失败、抛异常</td></tr><tr><td>死信队列</td><td>处理失败被丢到死信队列的消息</td></tr></tbody></table><p><strong>盯着前端页面没用,要去消息队列和消费者侧</strong>——这是异步架构排查的基本思维。</p><h2 id="七、服务治理" tabindex="-1">七、服务治理 <a class="header-anchor" href="#七、服务治理" aria-label="Permalink to &quot;七、服务治理&quot;">​</a></h2><p>服务一多,服务之间的调用需要统一管理,否则会成一锅粥。<strong>服务治理</strong>就是这一层的工作:</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Gateway%5B%22API%20%E7%BD%91%E5%85%B3%22%5D%0A%20%20Registry%5B%22%E6%B3%A8%E5%86%8C%E4%B8%AD%E5%BF%83%22%5D%0A%20%20Config%5B%22%E9%85%8D%E7%BD%AE%E4%B8%AD%E5%BF%83%22%5D%0A%20%20subgraph%20%E6%9C%8D%E5%8A%A1%E9%9B%86%E7%BE%A4%0A%20%20%20%20S1%5B%22%E7%94%A8%E6%88%B7%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20%20%20S2%5B%22%E8%AE%A2%E5%8D%95%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20%20%20S3%5B%22%E6%94%AF%E4%BB%98%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20end%0A%20%20Trace%5B%22%E9%93%BE%E8%B7%AF%E8%BF%BD%E8%B8%AA%22%5D%0A%20%20Metric%5B%22%E6%8C%87%E6%A0%87%E7%B3%BB%E7%BB%9F%22%5D%0A%0A%20%20Gateway%20--%3E%20S1%0A%20%20Gateway%20--%3E%20S2%0A%20%20Gateway%20--%3E%20S3%0A%20%20S1%20%3C--%3E%7C%22%E6%B3%A8%E5%86%8C%2F%E5%8F%91%E7%8E%B0%22%7C%20Registry%0A%20%20S2%20%3C--%3E%7C%22%E6%B3%A8%E5%86%8C%2F%E5%8F%91%E7%8E%B0%22%7C%20Registry%0A%20%20S3%20%3C--%3E%7C%22%E6%B3%A8%E5%86%8C%2F%E5%8F%91%E7%8E%B0%22%7C%20Registry%0A%20%20S1%20%3C--%3E%7C%22%E9%85%8D%E7%BD%AE%22%7C%20Config%0A%20%20S1%20-.-%3E%7C%22trace%22%7C%20Trace%0A%20%20S1%20-.-%3E%7C%22metric%22%7C%20Metric%0A"></div><h3 id="服务治理的核心能力" tabindex="-1">服务治理的核心能力 <a class="header-anchor" href="#服务治理的核心能力" aria-label="Permalink to &quot;服务治理的核心能力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>能力</th><th>解决什么</th></tr></thead><tbody><tr><td>服务发现</td><td>服务名动态映射到实例地址</td></tr><tr><td>配置中心</td><td>统一管理所有服务的配置</td></tr><tr><td>API 网关</td><td>统一入口、认证、路由、限流</td></tr><tr><td>限流熔断</td><td>防止慢服务拖垮上游</td></tr><tr><td>链路追踪</td><td>看一次请求经过了哪些服务</td></tr><tr><td>集中日志</td><td>多服务日志聚合查询</td></tr><tr><td>监控告警</td><td>服务级指标 + 业务指标</td></tr><tr><td>服务网格(Service Mesh)</td><td>把治理能力下沉到代理层</td></tr></tbody></table><h3 id="服务网格-治理能力下沉" tabindex="-1">服务网格:治理能力下沉 <a class="header-anchor" href="#服务网格-治理能力下沉" aria-label="Permalink to &quot;服务网格:治理能力下沉&quot;">​</a></h3><p><strong>Service Mesh</strong>(Istio、Linkerd、Consul Connect)把治理能力(限流、熔断、追踪、加密)做成应用旁边的 Sidecar 代理,<strong>应用代码不需要关心这些</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统方式               服务网格方式</span></span>
<span class="line"><span>应用 → 治理 SDK         应用 → Sidecar(治理逻辑)</span></span>
<span class="line"><span>        ↓                       ↓</span></span>
<span class="line"><span>       目标服务                目标服务</span></span></code></pre></div><p>服务网格的价值:</p><ul><li>治理能力与业务代码解耦</li><li>多语言统一治理(不需要每个语言都做 SDK)</li><li>治理策略集中管理</li></ul><p>但 Service Mesh 引入了复杂度,<strong>不到一定规模不建议上</strong>——小团队的微服务架构用传统 SDK 方式更轻量。</p><h2 id="八、完整企业级请求的链路" tabindex="-1">八、完整企业级请求的链路 <a class="header-anchor" href="#八、完整企业级请求的链路" aria-label="Permalink to &quot;八、完整企业级请求的链路&quot;">​</a></h2><p>一条企业级请求可能经过的对象:</p><p><img src="`+i+`" alt="企业级 504 排查要沿完整入口和后端链路收敛"></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>公网用户</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>CDN(静态资源加速)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>WAF(安全过滤)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>云负载均衡(LB)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>API 网关(认证、路由、限流)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Ingress / Nginx</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>后端服务 A(订单服务)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>[配置中心读取配置]</span></span>
<span class="line"><span>[Redis 缓存]</span></span>
<span class="line"><span>[消息队列 Kafka]</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>后端服务 B(用户服务)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>后端服务 C(支付服务)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>数据库</span></span></code></pre></div><p>每经过一个对象,都产生日志、指标、Trace 数据。架构图<strong>不只画对象,还要标注每一层的日志和指标在哪里收集</strong>——这决定出问题时去哪里查。</p><h3 id="一次-接口-504-的完整排查路径" tabindex="-1">一次&quot;接口 504&quot;的完整排查路径 <a class="header-anchor" href="#一次-接口-504-的完整排查路径" aria-label="Permalink to &quot;一次&quot;接口 504&quot;的完整排查路径&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现象:用户报&quot;提交订单接口 504&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 1 步:看入口 Nginx 日志</span></span>
<span class="line"><span>  → status=504 upstream_response_time=60.000</span></span>
<span class="line"><span>  → 入口等待后端超时,问题在后端</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 2 步:用入口日志中的 trace_id 拉链路追踪</span></span>
<span class="line"><span>  → 整个链路:网关 10ms → 订单服务 50ms → 报表服务 60s</span></span>
<span class="line"><span>  → 慢在报表服务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 3 步:看报表服务日志中的同一个 trace_id</span></span>
<span class="line"><span>  → 报表服务的日志显示卡在调用数据库</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 4 步:看数据库慢查询日志</span></span>
<span class="line"><span>  → 同一时间一条 SQL 扫了 3000 万行,缺索引</span></span>
<span class="line"><span></span></span>
<span class="line"><span>定位:报表查询的 SQL 缺索引,加索引后接口恢复正常</span></span></code></pre></div><p>整个排查链路只用 4 步、几分钟,得益于<strong>完整的可观测体系</strong>(入口日志 + 链路追踪 + 应用日志 + 慢查询日志)。</p><p>如果没有这套体系,排查只能靠猜——这就是为什么&quot;先建可观测,再上微服务&quot;是云原生时代的标配。</p><h2 id="九、企业架构的演进规律" tabindex="-1">九、企业架构的演进规律 <a class="header-anchor" href="#九、企业架构的演进规律" aria-label="Permalink to &quot;九、企业架构的演进规律&quot;">​</a></h2><p>总结一下企业架构形态的典型演进:</p><table tabindex="0"><thead><tr><th>阶段</th><th>形态</th><th>典型规模</th></tr></thead><tbody><tr><td>启动期</td><td>单机部署 + 单数据库</td><td>几百到几千用户</td></tr><tr><td>成长期</td><td>多实例 + 负载均衡 + Redis 缓存</td><td>几万到几十万用户</td></tr><tr><td>扩展期</td><td>数据库主从读写分离 + 消息队列 + CDN</td><td>几十万到百万用户</td></tr><tr><td>复杂期</td><td>微服务 + 容器化 + 完整可观测</td><td>百万到千万用户</td></tr><tr><td>大型化</td><td>服务网格 + 多机房 + 分库分表 + 流量治理</td><td>千万以上用户</td></tr><tr><td>超大型</td><td>异地多活 + 全球加速 + 复杂数据中台</td><td>海外大型互联网</td></tr></tbody></table><h3 id="演进的核心原则" tabindex="-1">演进的核心原则 <a class="header-anchor" href="#演进的核心原则" aria-label="Permalink to &quot;演进的核心原则&quot;">​</a></h3><p><strong>每一步演进都要解决具体业务痛点</strong>——不要为了&quot;看起来现代化&quot;提前引入复杂度。</p><table tabindex="0"><thead><tr><th>错误做法</th><th>后果</th></tr></thead><tbody><tr><td>5 人小团队上 K8s + 微服务</td><td>运维负担超过业务收益</td></tr><tr><td>业务还在验证阶段就分库分表</td><td>改业务时改架构,双倍工作量</td></tr><tr><td>月活 1000 的应用搞异地多活</td><td>成本远超价值</td></tr><tr><td>没有 CI/CD 就上微服务</td><td>部署成本指数级上升</td></tr></tbody></table><p>合理的演进节奏:<strong>业务驱动技术演进,而不是技术驱动架构升级</strong>。看到痛点 → 评估方案 → 渐进式引入 → 验证效果。</p><h3 id="技术债与架构演进" tabindex="-1">技术债与架构演进 <a class="header-anchor" href="#技术债与架构演进" aria-label="Permalink to &quot;技术债与架构演进&quot;">​</a></h3><p>每一次架构升级都会引入技术债——旧代码、旧模式、旧组件不会立刻消失,长期与新架构共存。<strong>承认技术债,有意识地偿还,而不是假装它不存在</strong>:</p><ul><li>给旧服务设置&quot;维护模式&quot;(不再加新功能,只修严重 bug)</li><li>安排专门的&quot;还债&quot;周期(每个迭代留 10%-20% 时间)</li><li>关键路径优先重构,边角不动</li><li>定期重新评估技术栈,该淘汰的尽快淘汰</li></ul><p>健康的企业架构演进,是<strong>业务增长 + 技术演进 + 技术债治理</strong>三件事的平衡。</p>`,123)])])}const B=a(l,[["render",o]]);export{g as __pageData,B as default};
